+import { createContext, useEffect, useMemo, useState } from "react";
+import { onAuthStateChanged, getAuth } from "firebase/auth";
+import { firebaseApp } from "../../utils/firebase";
+import { authApi } from "../../services/authApi";
+
+export const AuthContext = createContext(null);
+
+export function AuthProvider({ children }) {
+  const [user, setUser] = useState(null);
+  const [jwt, setJwt] = useState(null);
+  const [isLoading, setIsLoading] = useState(true);
+
+  useEffect(() => {
+    const storedToken = localStorage.getItem("qp_jwt");
+    const storedUser = localStorage.getItem("qp_user");
+    if (storedToken && storedUser) {
+      setJwt(storedToken);
+      setUser(JSON.parse(storedUser));
+    }
+
+    const auth = getAuth(firebaseApp);
+    const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
+      if (!firebaseUser) {
+        setUser(null);
+        setJwt(null);
+        localStorage.removeItem("qp_jwt");
+        localStorage.removeItem("qp_user");
+        setIsLoading(false);
+        return;
+      }
+
+      try {
+        const idToken = await firebaseUser.getIdToken();
+        const response = await authApi.loginWithFirebaseToken(idToken);
+        const nextUser = {
+          id: response.user_id,
+          email: response.email,
+          name: response.name,
+          role: response.role
+        };
+        setUser(nextUser);
+        setJwt(response.token);
+        localStorage.setItem("qp_jwt", response.token);
+        localStorage.setItem("qp_user", JSON.stringify(nextUser));
+      } catch (error) {
+        console.error("Failed to sync auth with backend", error);
+      } finally {
+        setIsLoading(false);
+      }
+    });
+
+    return () => unsubscribe();
+  }, []);
+
+  const value = useMemo(
+    () => ({
+      user,
+      jwt,
+      isAuthenticated: Boolean(jwt),
+      isLoading,
+      logout: () => {
+        setUser(null);
+        setJwt(null);
+        localStorage.removeItem("qp_jwt");
+        localStorage.removeItem("qp_user");
+      }
+    }),
+    [user, jwt, isLoading]
+  );
+
+  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
+}
+
