+            Join over <strong>2M</strong> global social users
+          </p>
+        </header>
+
+        <main>
+          <h1 className="auth-title">Welcome Back !</h1>
+          <p className="auth-switch-text">
+            Don&apos;t have an account? <button className="link-button">Create an account</button>
+          </p>
+
+          <form onSubmit={handleEmailPasswordLogin} className="auth-form">
+            {errors.form && <div className="form-error">{errors.form}</div>}
+
+            <div className="form-field">
+              <input
+                type="email"
+                placeholder="UserName/Email"
+                value={email}
+                onChange={(e) => setEmail(e.target.value)}
+                className={errors.email ? "input error" : "input"}
+                autoComplete="email"
+              />
+              {errors.email && <p className="field-error">{errors.email}</p>}
+            </div>
+
+            <div className="form-field">
+              <input
+                type="password"
+                placeholder="Password"
+                value={password}
+                onChange={(e) => setPassword(e.target.value)}
+                className={errors.password ? "input error" : "input"}
+                autoComplete="current-password"
+              />
+              {errors.password && <p className="field-error">{errors.password}</p>}
+            </div>
+
+            <button type="submit" className="primary-button" disabled={submitting}>
+              {submitting ? "Signing in..." : "Sign in"}
+            </button>
+          </form>
+
+          <div className="divider">
+            <span>or</span>
+          </div>
+
+          <button
+            type="button"
+            className="secondary-button google-button"
+            onClick={handleGoogleLogin}
+            disabled={submitting}
+          >
+            <span className="google-icon" aria-hidden="true">
+              🌐
+            </span>
+            <span>{submitting ? "Please wait..." : "Sign in with Google"}</span>
+          </button>
+
+          <p className="auth-footer-text">
+            Don&apos;t have an account? <button className="link-button">Sign up, It&apos;s free!</button>
