const PATH_BY_ROLE = {
  student: "/student",
  admin: "/admin",
  instructor: "/instructor"
};

export function normalizeRole(role) {
  if (role == null || role === "") return "";
  return String(role).toLowerCase().trim();
}

export function getDashboardPath(role) {
  const key = normalizeRole(role);
  return PATH_BY_ROLE[key] || "/student";
}

/**
 * After login: prefer `from` only if it matches the user's role home (or root).
 */
export function getPostLoginPath(user, fromPathname) {
  const dash = getDashboardPath(user?.role);
  if (!fromPathname || fromPathname === "/login") return dash;
  if (fromPathname === "/") return dash;

  const allowed = new Set(Object.values(PATH_BY_ROLE));
  if (allowed.has(fromPathname)) {
    const roleForPath = Object.entries(PATH_BY_ROLE).find(([, p]) => p === fromPathname)?.[0];
    if (roleForPath && normalizeRole(user?.role) === roleForPath) return fromPathname;
  }
  return dash;
}

import { Navigate, Outlet, useLocation } from "react-router-dom";
import { useAuth } from "../modules/auth/useAuth";
import { getDashboardPath, normalizeRole } from "../utils/roleRoutes";

export function RoleRoute({ allowedRoles }) {
  const { user, isAuthenticated, isLoading } = useAuth();
  const location = useLocation();

  if (isLoading) {
    return (
      <div className="fullscreen-center">
        <p>Loading...</p>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" replace state={{ from: location }} />;
  }

  const role = normalizeRole(user?.role);
  const allowed = allowedRoles.map((r) => normalizeRole(r));

  if (!allowed.includes(role)) {
    return <Navigate to={getDashboardPath(user?.role)} replace />;
  }

  return <Outlet />;
}

import { Navigate } from "react-router-dom";
import { useAuth } from "../modules/auth/useAuth";
import { getDashboardPath } from "../utils/roleRoutes";

export function RoleRedirect() {
  const { user, isAuthenticated, isLoading } = useAuth();

  if (isLoading) {
    return (
      <div className="fullscreen-center">
        <p>Checking authentication...</p>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }

  return <Navigate to={getDashboardPath(user?.role)} replace />;
}

