/** Max file size for direct client upload (matches backend expectation). */
export const QUESTION_PAPER_MAX_BYTES = 10 * 1024 * 1024; // 10MB

/** Values sent to backend as fileType */
export const FILE_TYPE = {
  PDF: "pdf",
  WORD: "word",
  EXCEL: "excel"
};

export const ALLOWED_EXTENSIONS = {
  [FILE_TYPE.PDF]: [".pdf"],
  [FILE_TYPE.WORD]: [".doc", ".docx"],
  [FILE_TYPE.EXCEL]: [".xls", ".xlsx"]
};

export const MIME_BY_FILE_TYPE = {
  [FILE_TYPE.PDF]: ["application/pdf"],
  [FILE_TYPE.WORD]: [
    "application/msword",
    "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
  ],
  [FILE_TYPE.EXCEL]: [
    "application/vnd.ms-excel",
    "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
  ]
};

import {
  ALLOWED_EXTENSIONS,
  FILE_TYPE,
  MIME_BY_FILE_TYPE,
  QUESTION_PAPER_MAX_BYTES
} from "./questionPaper.constants";

function extensionOf(fileName) {
  const i = fileName.lastIndexOf(".");
  if (i < 0) return "";
  return fileName.slice(i).toLowerCase();
}

export function detectFileType(file) {
  const name = file?.name || "";
  const ext = extensionOf(name);

  for (const [type, exts] of Object.entries(ALLOWED_EXTENSIONS)) {
    if (exts.includes(ext)) return type;
  }
  return null;
}

export function isMimeAllowedForFileType(fileType, mime) {
  const allowed = MIME_BY_FILE_TYPE[fileType];
  if (!allowed || !mime) return false;
  return allowed.includes(mime);
}

export function validateQuestionPaperFile(file) {
  if (!file) return "Select a file.";
  if (file.size > QUESTION_PAPER_MAX_BYTES) {
    return "File must be 10MB or smaller.";
  }
  const fileType = detectFileType(file);
  if (!fileType) {
    return "Only PDF, Word (.doc, .docx), or Excel (.xls, .xlsx) files are allowed.";
  }
  if (file.type && !isMimeAllowedForFileType(fileType, file.type)) {
    return "File type does not match the selected extension.";
  }
  return "";
}

export function buildMetadataPayload({
  subjectName,
  subjectCode,
  session,
  batch,
  fileKey,
  fileType,
  fileSize,
  questionPaperCreationDate
}) {
  return {
    subject_name: subjectName.trim(),
    subject_code: subjectCode.trim(),
    session: session.trim(),
    batch: batch.trim(),
    file_key: fileKey,
    file_type: fileType,
    file_size: fileSize,
    question_paper_creation_date: questionPaperCreationDate
  };
}

/**
 * Upload raw file bytes to a presigned URL (e.g. Supabase Storage).
 * Does not go through your API server.
 */
export async function uploadFileToSignedUrl(uploadUrl, file, contentType) {
  const ct = contentType || file.type || "application/octet-stream";
  const response = await fetch(uploadUrl, {
    method: "PUT",
    body: file,
    headers: {
      "Content-Type": ct
    }
  });

  if (!response.ok) {
    const text = await response.text().catch(() => "");
    throw new Error(text || `Upload failed (${response.status})`);
  }
}

import { apiClient } from "./apiClient";

const BASE = "/api/admin/question-papers";

export const questionPapersApi = {
  /**
   * Step 1: Get signed upload URL + file key (backend validates role & type).
   */
  async requestUploadUrl(fileName, fileType) {
    const { data } = await apiClient.post(`${BASE}/upload-url`, {
      fileName,
      fileType
    });
    return data;
  },

  /**
   * Step 4: Persist metadata after direct upload to storage.
   */
  async createQuestionPaper(metadata) {
    const { data } = await apiClient.post(BASE, metadata);
    return data;
  }
};

import { questionPapersApi } from "../../services/questionPapersApi";
import { uploadFileToSignedUrl } from "../../services/storageUpload";
import { buildMetadataPayload, detectFileType, validateQuestionPaperFile } from "./questionPaper.helpers";
import { MIME_BY_FILE_TYPE } from "./questionPaper.constants";

/**
 * Full flow: presigned URL → PUT to storage → POST metadata to API.
 */
export async function uploadQuestionPaper(file, formValues) {
  const fileError = validateQuestionPaperFile(file);
  if (fileError) {
    throw new Error(fileError);
  }

  const fileType = detectFileType(file);
  const { uploadUrl, fileKey } = await questionPapersApi.requestUploadUrl(file.name, fileType);

  if (!uploadUrl || !fileKey) {
    throw new Error("Invalid response from server (missing uploadUrl or fileKey).");
  }

  const contentType =
    file.type ||
    (MIME_BY_FILE_TYPE[fileType] && MIME_BY_FILE_TYPE[fileType][0]) ||
    "application/octet-stream";

  await uploadFileToSignedUrl(uploadUrl, file, contentType);

  const metadata = buildMetadataPayload({
    subjectName: formValues.subjectName,
    subjectCode: formValues.subjectCode,
    session: formValues.session,
    batch: formValues.batch,
    fileKey,
    fileType,
    fileSize: file.size,
    questionPaperCreationDate: formValues.questionPaperCreationDate
  });

  return questionPapersApi.createQuestionPaper(metadata);
}

import { useState } from "react";
import { Link } from "react-router-dom";
import { useAuth } from "../../modules/auth/useAuth";
import { getDashboardPath, normalizeRole } from "../../utils/roleRoutes";
import { QUESTION_PAPER_MAX_BYTES } from "../../modules/questionPapers/questionPaper.constants";
import { validateQuestionPaperFile } from "../../modules/questionPapers/questionPaper.helpers";
import { uploadQuestionPaper } from "../../modules/questionPapers/questionPaperUpload.service";

const SESSION_OPTIONS = [
  { value: "FN", label: "Forenoon (FN)" },
  { value: "AN", label: "Afternoon (AN)" }
];

function getErrorMessage(err) {
  const msg = err?.response?.data?.message;
  if (typeof msg === "string") return msg;
  if (Array.isArray(msg)) return msg.join(", ");
  return err?.message || "Something went wrong.";
}

export function QuestionPaperUploadPage() {
  const { user } = useAuth();
  const homePath = getDashboardPath(user?.role) || "/";

  const [file, setFile] = useState(null);
  const [fileError, setFileError] = useState("");
  const [subjectName, setSubjectName] = useState("");
  const [subjectCode, setSubjectCode] = useState("");
  const [session, setSession] = useState("FN");
  const [batch, setBatch] = useState("");
  const [questionPaperCreationDate, setQuestionPaperCreationDate] = useState(() =>
    new Date().toISOString().slice(0, 10)
  );
  const [formError, setFormError] = useState("");
  const [successMessage, setSuccessMessage] = useState("");
  const [phase, setPhase] = useState("idle");

  const isBusy = phase !== "idle" && phase !== "done";

  const onFileChange = (e) => {
    const f = e.target.files?.[0];
    setFile(f || null);
    setFileError(f ? validateQuestionPaperFile(f) : "");
    setSuccessMessage("");
    setFormError("");
  };

  const validateForm = () => {
    if (!subjectName.trim()) return "Subject name is required.";
    if (!subjectCode.trim()) return "Subject code is required.";
    if (!session.trim()) return "Session is required.";
    if (!batch.trim()) return "Batch is required.";
    if (!questionPaperCreationDate) return "Creation date is required.";
    return "";
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setFormError("");
    setSuccessMessage("");

    const fe = file ? validateQuestionPaperFile(file) : "Select a file.";
    if (fe) {
      setFileError(fe);
      return;
    }

    const ve = validateForm();
    if (ve) {
      setFormError(ve);
      return;
    }

    try {
      setPhase("url");
      await uploadQuestionPaper(file, {
        subjectName,
        subjectCode,
        session,
        batch,
        questionPaperCreationDate
      });
      setPhase("done");
      setSuccessMessage("Question paper uploaded and saved successfully.");
      setFile(null);
