import { questionPapersApi } from "../../services/questionPapersApi";
import { uploadFileToSignedUrl } from "../../services/storageUpload";
import { buildMetadataPayload, detectFileType, validateQuestionPaperFile } from "./questionPaper.helpers";
import { MIME_BY_FILE_TYPE } from "./questionPaper.constants";

/**
 * Full flow: presigned URL → PUT to storage → POST metadata to API.
 * @param {File} file
 * @param {object} formValues
 * @param {{ onPhase?: (phase: string) => void }} [hooks]
 */
export async function uploadQuestionPaper(file, formValues, hooks = {}) {
  const { onPhase } = hooks;

  const fileError = validateQuestionPaperFile(file);
  if (fileError) {
    throw new Error(fileError);
  }

  const fileType = detectFileType(file);

  onPhase?.("requesting-url");
  const { uploadUrl, fileKey } = await questionPapersApi.requestUploadUrl(file.name, fileType);

  if (!uploadUrl || !fileKey) {
    throw new Error("Invalid response from server (missing uploadUrl or fileKey).");
  }

  const contentType =
    file.type ||
    (MIME_BY_FILE_TYPE[fileType] && MIME_BY_FILE_TYPE[fileType][0]) ||
    "application/octet-stream";

  onPhase?.("uploading-storage");
  await uploadFileToSignedUrl(uploadUrl, file, contentType);

  onPhase?.("saving-metadata");
  const metadata = buildMetadataPayload({
    subjectName: formValues.subjectName,
    subjectCode: formValues.subjectCode,
    session: formValues.session,
    batch: formValues.batch,
    fileKey,
    fileType,
    fileSize: file.size,
    questionPaperCreationDate: formValues.questionPaperCreationDate
  });

  return questionPapersApi.createQuestionPaper(metadata);
}

