/**
 * Normalize backend shapes (snake_case or camelCase) for UI.
 */
export function normalizeQuestionPaper(raw) {
  if (!raw || typeof raw !== "object") return null;
  const id = raw.id ?? raw.paper_id ?? raw.paperId;
  return {
    id,
    subjectCode: raw.subject_code ?? raw.subjectCode ?? "",
    subjectName: raw.subject_name ?? raw.subjectName ?? "",
    batch: raw.batch ?? "",
    session: raw.session ?? "",
    uploadedAt: raw.created_at ?? raw.uploaded_at ?? raw.createdAt ?? raw.updated_at ?? null,
    fileKey: raw.file_key ?? raw.fileKey ?? "",
    fileType: raw.file_type ?? raw.fileType ?? "",
    fileSize: raw.file_size ?? raw.fileSize ?? null,
    questionPaperCreationDate:
      raw.question_paper_creation_date ?? raw.questionPaperCreationDate ?? "",
    ...raw
  };
}

export function formatUploadedAt(value) {
  if (value == null || value === "") return "—";
  try {
    const d = new Date(value);
    if (Number.isNaN(d.getTime())) return String(value);
    return d.toLocaleString(undefined, {
      dateStyle: "medium",
      timeStyle: "short"
    });
  } catch {
    return String(value);
  }
}

import { apiClient } from "./apiClient";

/** Admin-only: presign + create metadata */
const ADMIN_QP_BASE =
  import.meta.env.VITE_ADMIN_QUESTION_PAPERS_API_PATH || "/api/admin/question-papers";

/** Public listing, filters, detail, update, delete (RBAC on server) */
const QP_BASE = import.meta.env.VITE_QUESTION_PAPERS_API_PATH || "/api/question-papers";

export const questionPapersApi = {
  async requestUploadUrl(fileName, fileType) {
    const { data } = await apiClient.post(`${ADMIN_QP_BASE}/upload-url`, {
      fileName,
      fileType
    });
    return data;
  },

  async createQuestionPaper(metadata) {
    const { data } = await apiClient.post(ADMIN_QP_BASE, metadata);
    return data;
  },

  async listQuestionPapers(params = {}) {
    const { data } = await apiClient.get(QP_BASE, { params });
    return data;
  },

  async getSubjectCodeFilters() {
    const { data } = await apiClient.get(`${QP_BASE}/filters/subject-codes`);
    return data;
  },

  async getBatchFilters() {
    const { data } = await apiClient.get(`${QP_BASE}/filters/batches`);
    return data;
  },

  async getQuestionPaper(paperId) {
    const { data } = await apiClient.get(`${QP_BASE}/${paperId}`);
    return data;
  },

  async updateQuestionPaper(paperId, body) {
    const { data } = await apiClient.put(`${QP_BASE}/${paperId}`, body);
    return data;
  },

  async deleteQuestionPaper(paperId) {
    const { data } = await apiClient.delete(`${QP_BASE}/${paperId}`);
    return data;
  }
};

export function extractPaperList(payload) {
  if (Array.isArray(payload)) return payload;
  if (!payload || typeof payload !== "object") return [];
  if (Array.isArray(payload.papers)) return payload.papers;
  if (Array.isArray(payload.data)) return payload.data;
  if (Array.isArray(payload.questionPapers)) return payload.questionPapers;
  if (Array.isArray(payload.items)) return payload.items;
  return [];
}

export function extractFilterOptions(payload) {
  if (Array.isArray(payload)) return payload.filter((x) => x != null && x !== "");
  if (!payload || typeof payload !== "object") return [];
  const keys = ["codes", "subjectCodes", "batches", "values", "options", "data"];
  for (const k of keys) {
    if (Array.isArray(payload[k])) {
      return payload[k].filter((x) => x != null && x !== "");
    }
  }
  return [];
}

export function extractSinglePaper(payload) {
  if (!payload || typeof payload !== "object") return payload;
  return (
    payload.paper ??
    payload.questionPaper ??
    payload.data ??
    payload
  );
}

export function extractViewUrl(paper) {
  if (!paper || typeof paper !== "object") return null;
  return (
    paper.view_url ??
    paper.viewUrl ??
    paper.signed_url ??
    paper.signedUrl ??
    paper.download_url ??
    paper.downloadUrl ??
    paper.file_url ??
    paper.fileUrl ??
    null
  );
}

import { useEffect, useState } from "react";
import { questionPapersApi } from "../../services/questionPapersApi";
import { normalizeQuestionPaper } from "../../modules/questionPapers/questionPaper.model";

function getErrorMessage(err) {
  const msg = err?.response?.data?.message;
  if (typeof msg === "string") return msg;
  if (Array.isArray(msg)) return msg.join(", ");
  return err?.message || "Update failed.";
}

export function EditQuestionPaperModal({ paper: rawPaper, onClose, onSaved }) {
  const paper = normalizeQuestionPaper(rawPaper);
  const [subjectName, setSubjectName] = useState("");
  const [subjectCode, setSubjectCode] = useState("");
  const [session, setSession] = useState("FN");
  const [batch, setBatch] = useState("");
  const [questionPaperCreationDate, setQuestionPaperCreationDate] = useState("");
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    if (!paper?.id) return;
    setSubjectName(paper.subjectName || "");
    setSubjectCode(paper.subjectCode || "");
    setSession(paper.session || "FN");
    setBatch(paper.batch || "");
    setQuestionPaperCreationDate(
      paper.questionPaperCreationDate
        ? String(paper.questionPaperCreationDate).slice(0, 10)
        : ""
    );
    setError("");
  }, [paper?.id, rawPaper]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    if (!paper?.id) return;
    setSaving(true);
    try {
      await questionPapersApi.updateQuestionPaper(paper.id, {
        subject_name: subjectName.trim(),
        subject_code: subjectCode.trim(),
        session: session.trim(),
        batch: batch.trim(),
        question_paper_creation_date: questionPaperCreationDate
      });
      onSaved?.();
      onClose?.();
    } catch (err) {
      setError(getErrorMessage(err));
    } finally {
      setSaving(false);
    }
  };

  if (!paper?.id) return null;

  return (
    <div className="qp-modal-backdrop" role="presentation" onClick={onClose}>
      <div
        className="qp-modal"
        role="dialog"
        aria-labelledby="qp-edit-title"
        onClick={(e) => e.stopPropagation()}
      >
        <h2 id="qp-edit-title">Edit question paper</h2>
        <form onSubmit={handleSubmit} className="upload-form">
          {error && (
            <div className="form-error upload-banner" role="alert">
              {error}
            </div>
          )}
          <div className="form-field">
            <label htmlFor="edit-subject-name">Subject name</label>
            <input
              id="edit-subject-name"
              className="input"
              value={subjectName}
              onChange={(e) => setSubjectName(e.target.value)}
              required
              disabled={saving}
            />
          </div>
          <div className="form-field">
            <label htmlFor="edit-subject-code">Subject code</label>
            <input
              id="edit-subject-code"
              className="input"
              value={subjectCode}
              onChange={(e) => setSubjectCode(e.target.value)}
              required
              disabled={saving}
            />
          </div>
          <div className="form-field">
            <label htmlFor="edit-session">Session</label>
            <select
              id="edit-session"
              className="input"
              value={session}
              onChange={(e) => setSession(e.target.value)}
              disabled={saving}
            >
              <option value="FN">Forenoon (FN)</option>
              <option value="AN">Afternoon (AN)</option>
            </select>
          </div>
          <div className="form-field">
            <label htmlFor="edit-batch">Batch</label>
            <input
              id="edit-batch"
              className="input"
              value={batch}
              onChange={(e) => setBatch(e.target.value)}
              required
              disabled={saving}
            />
          </div>
          <div className="form-field">
            <label htmlFor="edit-date">Question paper date</label>
            <input
              id="edit-date"
              type="date"
              className="input"
              value={questionPaperCreationDate}
              onChange={(e) => setQuestionPaperCreationDate(e.target.value)}
              required
              disabled={saving}
            />
          </div>
          <div className="qp-modal-actions">
            <button type="button" className="qp-btn qp-btn-secondary" onClick={onClose} disabled={saving}>
              Cancel
            </button>
            <button type="submit" className="primary-button" disabled={saving}>
              {saving ? "Saving…" : "Save"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

import { useCallback, useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import { useAuth } from "../../modules/auth/useAuth";
import { normalizeRole } from "../../utils/roleRoutes";
import { getDashboardPath } from "../../utils/roleRoutes";
import { questionPapersApi } from "../../services/questionPapersApi";
import { extractFilterOptions, extractPaperList } from "../../modules/questionPapers/apiResponse.helpers";
import { normalizeQuestionPaper } from "../../modules/questionPapers/questionPaper.model";
import { QuestionPaperCard } from "./QuestionPaperCard";
import { EditQuestionPaperModal } from "./EditQuestionPaperModal";

function getErrorMessage(err) {
  const msg = err?.response?.data?.message;
  if (typeof msg === "string") return msg;
  if (Array.isArray(msg)) return msg.join(", ");
  return err?.message || "Failed to load question papers.";
}

function canManagePapers(user) {
  const r = normalizeRole(user?.role);
  return r === "admin" || r === "instructor";
}

export function QuestionPapersListPage() {
  const { user } = useAuth();
  const homePath = getDashboardPath(user?.role) || "/";
  const showActions = canManagePapers(user);

  const [papers, setPapers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [listError, setListError] = useState("");
  const [subjectCodes, setSubjectCodes] = useState([]);
  const [batches, setBatches] = useState([]);
  const [filterSubjectCode, setFilterSubjectCode] = useState("");
  const [filterBatch, setFilterBatch] = useState("");
  const [searchText, setSearchText] = useState("");
  const [editingPaper, setEditingPaper] = useState(null);

  const loadFilters = useCallback(async () => {
    try {
      const [codesRes, batchesRes] = await Promise.all([
        questionPapersApi.getSubjectCodeFilters(),
        questionPapersApi.getBatchFilters()
      ]);
      setSubjectCodes(extractFilterOptions(codesRes));
      setBatches(extractFilterOptions(batchesRes));
    } catch {
      setSubjectCodes([]);
      setBatches([]);
    }
  }, []);

  const loadList = useCallback(async () => {
    setLoading(true);
    setListError("");
    try {
      const params = {};
      if (filterSubjectCode) params.subject_code = filterSubjectCode;
      if (filterBatch) params.batch = filterBatch;
      const data = await questionPapersApi.listQuestionPapers(params);
      setPapers(extractPaperList(data));
    } catch (err) {
      setListError(getErrorMessage(err));
      setPapers([]);
    } finally {
      setLoading(false);
    }
  }, [filterSubjectCode, filterBatch]);

  useEffect(() => {
    loadFilters();
  }, [loadFilters]);

  useEffect(() => {
    loadList();
  }, [loadList]);

  const filteredPapers = useMemo(() => {
    const q = searchText.trim().toLowerCase();
    if (!q) return papers;
    return papers.filter((raw) => {
      const p = normalizeQuestionPaper(raw);
      const name = (p.subjectName || "").toLowerCase();
      const code = (p.subjectCode || "").toLowerCase();
      return name.includes(q) || code.includes(q);
    });
  }, [papers, searchText]);

  const handleDelete = async (paper) => {
    const p = normalizeQuestionPaper(paper);
    if (!p?.id) return;
    if (!window.confirm(`Delete question paper “${p.subjectName || p.subjectCode}”? This cannot be undone.`)) {
      return;
    }
    try {
      await questionPapersApi.deleteQuestionPaper(p.id);
      await loadList();
    } catch (err) {
      window.alert(getErrorMessage(err));
    }
  };

  return (
    <div className="dashboard-page qp-browse-page">
      <div className="qp-browse-header">
        <p className="upload-breadcrumb">
          <Link to={homePath}>Dashboard</Link>
          <span aria-hidden="true"> / </span>
          <span>Question papers</span>
        </p>
        <h1>Question papers</h1>
        <p className="dashboard-hint">Browse and open papers. Filters use server lists; search narrows the current results.</p>
      </div>

      <div className="qp-toolbar">
        <div className="qp-filters">
          <label className="qp-filter">
            <span>Subject code</span>
            <select
              className="input"
              value={filterSubjectCode}
              onChange={(e) => setFilterSubjectCode(e.target.value)}
            >
              <option value="">All</option>
              {subjectCodes.map((c) => (
                <option key={String(c)} value={String(c)}>
                  {String(c)}
                </option>
              ))}
            </select>
          </label>
          <label className="qp-filter">
            <span>Batch</span>
            <select
              className="input"
              value={filterBatch}
              onChange={(e) => setFilterBatch(e.target.value)}
            >
              <option value="">All</option>
              {batches.map((b) => (
                <option key={String(b)} value={String(b)}>
                  {String(b)}
                </option>
              ))}
            </select>
          </label>
          <label className="qp-filter qp-filter-grow">
            <span>Search</span>
            <input
              className="input"
              type="search"
              placeholder="Filter by name or code…"
              value={searchText}
              onChange={(e) => setSearchText(e.target.value)}
            />
          </label>
        </div>
      </div>

      {listError && (
        <div className="form-error upload-banner qp-list-error" role="alert">
          {listError}
        </div>
      )}

      {loading ? (
        <p className="qp-loading">Loading question papers…</p>
      ) : filteredPapers.length === 0 ? (
        <p className="qp-empty">No question papers match your filters.</p>
      ) : (
        <div className="qp-grid">
          {filteredPapers.map((raw) => (
            <QuestionPaperCard
              key={normalizeQuestionPaper(raw)?.id ?? JSON.stringify(raw)}
              raw={raw}
              showActions={showActions}
              onEdit={(p) => setEditingPaper(p)}
              onDelete={handleDelete}
            />
          ))}
        </div>
      )}

      {editingPaper && (
        <EditQuestionPaperModal
          paper={editingPaper}
          onClose={() => setEditingPaper(null)}
          onSaved={() => loadList()}
        />
      )}
    </div>
  );
}

import { useEffect, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { useAuth } from "../../modules/auth/useAuth";
import { getDashboardPath } from "../../utils/roleRoutes";
import { questionPapersApi } from "../../services/questionPapersApi";
import { extractSinglePaper, extractViewUrl } from "../../modules/questionPapers/apiResponse.helpers";
import { formatUploadedAt, normalizeQuestionPaper } from "../../modules/questionPapers/questionPaper.model";

function getErrorMessage(err) {
  const msg = err?.response?.data?.message;
  if (typeof msg === "string") return msg;
  if (Array.isArray(msg)) return msg.join(", ");
  return err?.message || "Could not load this question paper.";
}

export function QuestionPaperDetailPage() {
  const { paperId } = useParams();
  const { user } = useAuth();
  const homePath = getDashboardPath(user?.role) || "/";

  const [raw, setRaw] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      if (!paperId) return;
      setLoading(true);
      setError("");
      try {
        const data = await questionPapersApi.getQuestionPaper(paperId);
        if (!cancelled) setRaw(extractSinglePaper(data));
      } catch (err) {
        if (!cancelled) setError(getErrorMessage(err));
      } finally {
        if (!cancelled) setLoading(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, [paperId]);

  const paper = normalizeQuestionPaper(raw);
  const viewUrl = extractViewUrl(paper) || extractViewUrl(raw);

  return (
    <div className="dashboard-page qp-detail-page">
      <div className="dashboard-card qp-detail-card">
        <p className="upload-breadcrumb">
          <Link to={homePath}>Dashboard</Link>
          <span aria-hidden="true"> / </span>
          <Link to="/question-papers">Question papers</Link>
          <span aria-hidden="true"> / </span>
          <span>View</span>
        </p>

        {loading && <p>Loading…</p>}
        {error && (
          <div className="form-error upload-banner" role="alert">
            {error}
          </div>
        )}

        {!loading && !error && paper?.id && (
          <>
            <h1>{paper.subjectName || "Question paper"}</h1>
            <dl className="dashboard-meta qp-detail-meta">
              <div>
                <dt>Subject code</dt>
                <dd>{paper.subjectCode || "—"}</dd>
              </div>
              <div>
                <dt>Batch</dt>
                <dd>{paper.batch || "—"}</dd>
              </div>
              <div>
                <dt>Session</dt>
                <dd>{paper.session || "—"}</dd>
              </div>
              <div>
                <dt>Uploaded at</dt>
                <dd>{formatUploadedAt(paper.uploadedAt)}</dd>
              </div>
              <div>
                <dt>Paper date</dt>
                <dd>{paper.questionPaperCreationDate || "—"}</dd>
              </div>
              <div>
                <dt>File type</dt>
                <dd>{paper.fileType || "—"}</dd>
              </div>
            </dl>

            {viewUrl ? (
              <p className="qp-detail-actions">
                <a
                  href={viewUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="primary-button qp-open-btn"
                >
                  Open / view file
                </a>
              </p>
            ) : (
              <p className="dashboard-hint">
                No view URL was returned by the API. Ensure{" "}
                <code>GET /api/question-papers/:paperId</code> includes a signed URL field (e.g.{" "}
                <code>viewUrl</code>, <code>signedUrl</code>, or <code>downloadUrl</code>).
              </p>
            )}
          </>
        )}
      </div>
    </div>
  );
}

