import { apiClient } from "./apiClient";

const BASE = "/api/auth";

export const usersApi = {
  async getAllUsers() {
    const { data } = await apiClient.get(`${BASE}/users`);
    return data;
  },

  /**
   * @param {string|number} userId
   * @param {"student" | "instructor" | "admin"} role
   */
  async updateUserRole(userId, role) {
    const { data } = await apiClient.patch(`${BASE}/users/${userId}/role`, { role });
    return data;
  },

  /**
   * Remove a user. Wire this route on the backend if you need delete (e.g. DELETE /auth/users/:userId).
   */
  async deleteUser(userId) {
    const { data } = await apiClient.delete(`${BASE}/users/${userId}`);
    return data;
  }
};

export function normalizeUser(raw) {
  if (!raw || typeof raw !== "object") return null;
  const id = raw.id ?? raw.user_id ?? raw.userId;
  return {
    ...raw,
    id,
    email: raw.email ?? "",
    name: raw.name ?? raw.full_name ?? raw.fullName ?? "",
    role: raw.role != null ? String(raw.role).toLowerCase() : "",
    createdAt: raw.created_at ?? raw.createdAt ?? null,
    updatedAt: raw.updated_at ?? raw.updatedAt ?? null
  };
}

export function extractUsersList(payload) {
  if (Array.isArray(payload)) return payload;
  if (!payload || typeof payload !== "object") return [];
  if (Array.isArray(payload.users)) return payload.users;
  if (Array.isArray(payload.data)) return payload.data;
  return [];
}

import { useCallback, useEffect, useState } from "react";
import { useAuth } from "../../modules/auth/useAuth";
import { normalizeRole } from "../../utils/roleRoutes";
import { usersApi } from "../../services/usersApi";
import { extractUsersList, normalizeUser } from "../../modules/users/user.model";
import { formatUploadedAt } from "../../modules/questionPapers/questionPaper.model";

const ASSIGNABLE_ROLES = [
  { value: "student", label: "Student" },
  { value: "instructor", label: "Instructor" }
];

function getErrorMessage(err) {
  const msg = err?.response?.data?.message;
  if (typeof msg === "string") return msg;
  if (Array.isArray(msg)) return msg.join(", ");
  return err?.message || "Request failed.";
}

export function AdminUsersTable() {
  const { user: currentUser } = useAuth();
  const currentId = currentUser?.id != null ? String(currentUser.id) : null;

  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [pendingId, setPendingId] = useState(null);

  const load = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const data = await usersApi.getAllUsers();
      setRows(extractUsersList(data));
    } catch (err) {
      setError(getErrorMessage(err));
      setRows([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  const handleRoleChange = async (rawRow, nextRole) => {
    const u = normalizeUser(rawRow);
    if (!u?.id) return;
    const idStr = String(u.id);
    if (idStr === currentId) {
      window.alert("You cannot change your own role here.");
      return;
    }
    if (normalizeRole(u.role) === "admin") {
      window.alert("Admin accounts cannot be reassigned from this dropdown.");
      return;
    }
    setPendingId(idStr);
    try {
      await usersApi.updateUserRole(u.id, nextRole);
      await load();
    } catch (err) {
      window.alert(getErrorMessage(err));
    } finally {
      setPendingId(null);
    }
  };

  const handleDelete = async (rawRow) => {
    const u = normalizeUser(rawRow);
    if (!u?.id) return;
    const idStr = String(u.id);
    if (idStr === currentId) {
      window.alert("You cannot delete your own account.");
      return;
    }
    if (!window.confirm(`Delete user ${u.email || u.name || idStr}? This cannot be undone.`)) {
      return;
    }
    setPendingId(idStr);
    try {
      await usersApi.deleteUser(u.id);
      await load();
    } catch (err) {
      window.alert(getErrorMessage(err));
    } finally {
      setPendingId(null);
    }
  };

  if (loading) {
    return <p className="admin-users-loading">Loading users…</p>;
  }

  if (error) {
    return (
      <div className="form-error upload-banner" role="alert">
        {error}
      </div>
    );
  }

  if (rows.length === 0) {
    return <p className="admin-users-empty">No users returned.</p>;
  }

  return (
    <div className="admin-users-table-wrap">
      <table className="admin-users-table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Name</th>
            <th>Email</th>
            <th>Role</th>
            <th>Created</th>
            <th>Updated</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((raw) => {
            const u = normalizeUser(raw);
            const idStr = u?.id != null ? String(u.id) : "";
            const isSelf = currentId != null && idStr === currentId;
            const isAdmin = normalizeRole(u.role) === "admin";
            const busy = pendingId === idStr;

            return (
              <tr key={idStr || u.email}>
                <td className="admin-users-mono">{idStr || "—"}</td>
                <td>{u.name || "—"}</td>
                <td>{u.email || "—"}</td>
                <td>
                  {isAdmin ? (
                    <span className="admin-users-role-pill admin">admin</span>
                  ) : (
                    <select
                      className="input admin-users-role-select"
                      value={normalizeRole(u.role) || "student"}
                      disabled={busy || isSelf}
                      onChange={(e) => handleRoleChange(raw, e.target.value)}
                      title={isSelf ? "Cannot change your own role" : "Change role"}
                    >
                      {ASSIGNABLE_ROLES.map((opt) => (
                        <option key={opt.value} value={opt.value}>
                          {opt.label}
                        </option>
                      ))}
                    </select>
                  )}
                </td>
                <td>{formatUploadedAt(u.createdAt)}</td>
                <td>{formatUploadedAt(u.updatedAt)}</td>
                <td>
                  <button
                    type="button"
                    className="qp-btn qp-btn-danger admin-users-delete"
                    disabled={busy || isSelf || isAdmin}
                    title={
                      isSelf
                        ? "Cannot delete yourself"
                        : isAdmin
                          ? "Remove admin via backend if needed"
                          : "Delete user"
                    }
                    onClick={() => handleDelete(raw)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

